-- MHP Historical Pricing Seed Data
-- Generated from 3 years of construction estimates (2023-2026)
-- 240 project files, 28,941 line items analyzed

-- Seed products table with MHP standard line items
ON CONFLICT DO NOTHING;

-- Seed unified_pricing with historical baseline prices
SELECT p.id, p.default_unit_price, 
  CASE WHEN (p.specs->>'occurrences')::int >= 50 THEN 0.95
       WHEN (p.specs->>'occurrences')::int >= 20 THEN 0.85
       WHEN (p.specs->>'occurrences')::int >= 10 THEN 0.75
       ELSE 0.60 END,
  (p.specs->>'occurrences')::int,
  'green',
  NOW()
FROM products p
WHERE p.source = 'historical_mhp'
ON CONFLICT DO NOTHING;